.toolbar {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  justify-content: space-between;
}

.toolbar > .grow {
  flex: 1 1 auto;
  min-width: 0;
}

.shell {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: auto 1fr auto;
  min-height: 100vh;
}

/* Illustrative only — verify engine support */
.card {
  color: if(
    prefers-color-scheme: dark;
    white;
    black
  );
}

.container {
  display: grid;
  gap: 1rem;
  grid-template-columns: repeat(3, 1fr);
  /* masonry-related keywords vary by implementation */
}

/* Pseudocode shape — check MDN for shipping syntax */
.anchor { anchor-name: --trigger; }
.tooltip {
  position: absolute;
  position-anchor: --trigger;
  inset-area: bottom;
}

.title {
  /* Illustrative — verify property availability */
  text-box-trim: trim-both;
  text-box-edge: cap alphabetic;
}

@keyframes fade-in {
  from { opacity: 0 }
  to { opacity: 1 }
}
.reveal {
  animation: fade-in linear both;
  animation-timeline: view();
  animation-range: entry 0% cover 40%;
}

/* Sass-style illustration — not valid vanilla CSS */
/* @mixin button($bg) { background: $bg; } */

:root {
  --btn-bg: oklch(0.55 0.15 250);
}
.btn {
  background: var(--btn-bg);
}

section {
  margin-trim: block;
  /* Illustrative — confirm engine support */
}

.cta {
  background: var(--brand);
  /* Conceptual API — check shipping name/syntax */
  color: contrast-color(var(--brand));
}

.hero {
  /* Pseudocode — engines may use different names */
  opacity: progress(scroll(root block), 0px, 200px);
}

document.startViewTransition(() => {
  document.body.classList.toggle('theme-dark');
});

::view-transition-old(root),
::view-transition-new(root) {
  animation-duration: 300ms;
}

:root {
  --primary: oklch(0.55 0.2 250);
  --radius: 12px;
}
.button {
  background: var(--primary);
  border-radius: var(--radius);
}

body {
  font-size: clamp(1rem, 0.25vw + 0.9rem, 1.125rem);
}
h1 {
  font-size: clamp(1.25rem, 2vw + 1rem, 2.25rem);
}

.card-wrap {
  container-type: inline-size;
  container-name: card;
}
@container card (min-width: 500px) {
  .card {
    flex-direction: row;
    gap: 1.5rem;
  }
}

.card:has(img) {
  border: 2px solid var(--brand);
}
.form-field:has(:user-invalid) {
  border-color: var(--danger);
}

@layer reset, tokens, components, utilities;

@layer reset {
  *, *::before, *::after { box-sizing: border-box; }
}

@layer utilities {
  .hidden { display: none !important; }
}

.hero {
  min-height: 100dvh;
  min-height: 100svh; /* fallback chain */
}
.modal {
  max-height: 90dvh;
}

.card {
  padding: 1rem;
  border-radius: 12px;

  &:hover {
    box-shadow: var(--shadow-lg);
  }

  & .title {
    font-weight: 600;
  }
}

:root {
  color-scheme: light dark;
}
body {
  background: light-dark(white, #0a0a0a);
  color: light-dark(#171717, #fafafa);
}

.popover {
  opacity: 1;
  transform: scale(1);
  transition: opacity 200ms, transform 200ms;
}

@starting-style {
  .popover {
    opacity: 0;
    transform: scale(0.96);
  }
}

.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
}
.grid > .tile {
  display: grid;
  grid-template-columns: subgrid;
  grid-column: span 2;
}

.btn:hover {
  background: color-mix(in oklab, var(--brand) 70%, white);
}
.badge {
  color: color-mix(in srgb, red 50%, white);
}

/* Conceptual — check Baseline / MDN */
@container scroll-state(stuck: top) {
  .bar {
    box-shadow: var(--shadow);
  }
}

select {
  /* appearance: base-select; — when supported */
  font: inherit;
  border-radius: 8px;
}

/* Illustrative — NOT portable CSS today */
/* @function --half(--v) { result: calc(var(--v) / 2); } */

:root {
  --space: 16px;
}
.gap-half {
  gap: calc(var(--space) / 2);
}

.list > li {
  animation: rise 400ms ease both;
  animation-delay: calc(60ms * sibling-index());
}
